def apply_exif_orientation(raster: Raster, orientation: int | None) -> Raster:
    if orientation is None or orientation <= 1 or orientation > 8:
        return raster

    source = raster.to_rgb()
    if orientation == 2:
        return _flip_horizontal(source)
    if orientation == 3:
        return _rotate_180(source)
    if orientation == 4:
        return _flip_vertical(source)
    if orientation == 5:
        return _transpose(source)
    if orientation == 6:
        return _rotate_90_cw(source)
    if orientation == 7:
        return _transverse(source)
    if orientation == 8:
        return _rotate_90_ccw(source)
    return source

