def _rotate_90_cw(raster: Raster) -> Raster:
    width, height = raster.width, raster.height
    output = bytearray(height * width * 3)
    for row in range(height):
        for col in range(width):
            source_index = (row * width + col) * 3
            new_row = col
            new_col = height - 1 - row
            dest_index = (new_row * height + new_col) * 3
            output[dest_index : dest_index + 3] = raster.data[source_index : source_index + 3]
    return Raster(height, width, 3, output)

